    # "wasm" - show WASM module info
    mov     edi, offset cmd_wasm
    call    utils_strcmp
    test    eax, eax
    jz      .do_wasm

    # "wasmrun <file>" - run WASM from file
    mov     edi, offset cmd_wasmrun
    mov     esi, offset shell_cmd_buf
    mov     ecx, 8                 # "wasmrun " length
    call    utils_strncmp
    test    eax, eax
    jz      .do_wasmrun

    # "wasmtest2" - WASM const add test (3+5=8)
