    .ascii  "WRITETESTWRITETESTWRITETESTWRITETESTWRITETESTWRITETESTWRITETESTWRITETEST"
    .ascii  "WRITETESTWRITETESTWRITETESTWRITETESTWRITETESTWRITETESTWRITETESTWRITETEST"
    .ascii  "WRITETESTWRITETESTWRITETESTWRITETEST"  # 512 bytes total (64 * 8 = 512)
    # code section: push args, call fatwrite, return
